#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    vec3 main = texture( sampler_main, vUv ).xyz;
    vec3 mblur = GetBlur1( vUv );
    main = ( (main-mblur*.5)*3 );
    float zoom = 1+.5*( (q9*vUvOriginal.y-q8*vUvOriginal.x)*6+vRadius*sin(vAngle+2-q3-q4)*mblur.z*3)*(.01+(q1-q2)*.01);
    float rot = (mblur.y-mblur.x)*(q7-q8)*.5;
    vec2 zcr = vec2(.5,.5);
    vec2 cr = vec2(.5,.5);
    vec2 newuv = vUv;

    ///////////////////rotation////////////////
    newuv = vUv - cr;
    float s = sin(rot);
    float c = cos(rot);
    newuv = vec2( (vUv.x-cr.x)*c-(vUv.y-cr.y)*s , (vUv.x-cr.x)*s+(vUv.y-cr.y)*c  );
    newuv = newuv + cr;
    ///////////////////rotation////////////////

    ///////////////////zoom////////////////
    newuv = newuv-zcr;
    newuv = newuv * zoom;
    newuv= newuv+zcr;
    ///////////////////zoom////////////////


    vec3 colorwarp = texture( sampler_main, newuv );

    vec3 color = texture(sampler_rand02, newuv ).xyz;
//    ret = ( (  (colorwarp*main*3-normalize(color)) ) );
    ret= mix(colorwarp,main*color,1-sin((color-colorwarp)*6));
vec3 ret1=ret;
ret.z=.3-ret1.x;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q13         && ret.x<= q24*q11        )ret.y -= (noise9).x*.5;
ret.z=.3-ret1.y;
if(ret.y> q22*q11         && ret.y<= q25*q12        )ret.z -= (noise9).y*.5;
ret.y=.3-ret1.x;
if(ret.z> q23*q12         && ret.z<= q26*q13        )ret.x -= (noise9).z*.5;
ret1=ret;
ret.x=.3-ret1.z;
ret.y=.3-ret1.z;
ret.x=.3-ret1.y;
ret1=ret;
ret.x=.3-ret1.x;
ret.y=.3-ret1.y;
ret.z=.3-ret1.z;
    // darken (decay) over uTime
    ret *= 0.96; //or try: ret -= 0.004;


ret.xyz = texture(sampler_main, vUvOriginal).xyz*vec3(.97,1,.97) - vec3(.03,0,.03);

ret.z += GetBlur1(vUvOriginal).z*.45;
ret.x += GetBlur1(vUvOriginal).z*.05 + GetBlur3(vUvOriginal).z*.05;
ret.z -= ret.x;

vec2 pixelsize = uTexSize.zw;
ret.y = clamp01(texture( sampler_pw_main,vUvOriginal).y);

float1 conway = texture( sampler_pw_main, vUvOriginal + vec2(-1,-1)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(0,-1)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(1,-1)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(-1,0)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(1,0)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(-1,1)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(0,1)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(1,1)*pixelsize).y;

float1 test = q5*(1-GetBlur1(vUvOriginal).y)*(1-GetBlur2(vUvOriginal).y)*(1-GetBlur3(vUvOriginal).y);

conway -= texture( sampler_pw_main, vUvOriginal).x;


if (conway > 1) {
if (clamp01(ret.y) == 0) {
ret.y = floor(test*99)*1;
}
}

ret.y -= ret.x;

ret.xyz -= audioLow/7-audioMid/11.2 ;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw*8;
    vec3 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );
    vec2 uv_y = vUv-vec2(dx.y,dy.y)*0.4;

    vec2 uv_dx = vUv - vec2(dx.x,dy.x)*1;
    vec2 uv_dz = vUv + vec2(dx.z,dy.z)*uTexSize.zw*256;
    vec2 uv_dy = vUv - vec2(dx.y,dy.y)*uTexSize.zw*80;

ret = GetPixel(vUv).y*0.2;

vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((uv_dz.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q13         && ret.x<= q23*q11        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q11         && ret.y<= q22*q12        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q12         && ret.z<= q21*q13        )ret.y -= (noise9).z*.5;
ret = mix(vec3(0.2,0,0.1),vec3(0.8,0.6,0),GetPixel(uv_dz).y);
ret = mix(ret,1,GetPixel(vUv).z*1);

ret = mix(ret, vec3(0.8,0,1.5), length(vec2(dx.x,dy.x)));

ret = mix(clamp01(ret),0,clamp01(GetPixel(uv_dz).x-GetBlur1(vUv).z*1.5));

//ret = GetPixel(vUv).y;

  fragColor = ret;
}
